function computeRegularWeight(cocktail: CocktailSeed, difficultyId: DifficultyId) {
  const tier = cocktail.popularityTier as CocktailPopularityTier
  if (tier === 'obscure') return 0

  if (difficultyId === 'level-1') return tier === 'popular' ? 2.4 : 1.0
  if (difficultyId === 'level-2') return tier === 'popular' ? 1.8 : 1.0
  return tier === 'popular' ? 2.0 : 1.0
}

export const cocktailQuestionBank: CocktailQuestionSource[] = cocktailSeeds.map((cocktail) => ({
  ...cocktail,
  weightModifier: computeRegularWeight(cocktail, 'level-1'),
}))

export const cocktailQuestionBankById = new Map(
  cocktailQuestionBank.map((cocktail) => [cocktail.id, cocktail]),
)

export function applyRegularCocktailWeights(difficultyId: DifficultyId) {
  return cocktailSeeds
    .filter((c) => c.popularityTier !== 'obscure')
    .map((cocktail) => ({
      ...cocktail,
      weightModifier: computeRegularWeight(cocktail, difficultyId),
    }))
}

export function getObscureCocktailPool() {
  return cocktailSeeds
    .filter((c) => c.popularityTier === 'obscure')
    .map((cocktail) => ({ ...cocktail, weightModifier: 1 }))
}
